class Solution {
public:
    string maximumBinaryString(string binary) {
        int n = binary.length();
        vector<int> dp(n, 0);

        for (int i = 1; i < n; i++) {
            if (binary[i] == '0') {
                dp[i] = dp[i - 1] + 1;
            }
        }

        int max_result = 0;
        for (int i = n - 1; i >= 0; i--) {
            if (binary[i] == '0') {
                max_result = max(max_result, dp[i]);
            }
        }

        string result = "";
        for (int i = n - 1; i >= 0; i--) {
            if (binary[i] == '0') {
                result += dp[i];
            } else {
                result += binary[i];
            }
        }

        return result;
    }
};
